section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/api-error-handling.json",
  "title": "API Error Handling",
  "type": "object",
  "required": [
    "artefact_id",
    "api_id",
    "envelope_standard",
    "type_uri_base",
    "trace_header",
    "error_catalogue",
    "field_level_validation",
    "raw_exception_banned",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "api_id": {
      "type": "string",
      "description": "service id or repo slug",
      "minLength": 1
    },
    "envelope_standard": {
      "type": "string",
      "description": "rfc7807|json-api|other (must be named explicitly)",
      "minLength": 1
    },
    "type_uri_base": {
      "type": "string",
      "description": "base URI for error type identifiers (https://api.example.com/errors/)",
      "minLength": 1
    },
    "trace_header": {
      "type": "string",
      "description": "request header name carrying the traceId (e.g. X-Request-Id, traceparent)",
      "minLength": 1
    },
    "error_catalogue": {
      "type": "array",
      "description": "list of {code, type_uri, title, status} entries \u2014 closed list",
      "minItems": 1
    },
    "field_level_validation": {
      "type": "boolean",
      "description": "true when validation errors include the `errors[]` field-level array"
    },
    "raw_exception_banned": {
      "type": "boolean",
      "description": "must be true; raw stack traces in responses are forbidden"
    }
  },
  "additionalProperties": false
}
